#include<bits/stdc++.h>
using namespace std;
long long n,a[200010],b[200010],s[200010];
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=a[i];
    }
    sort(b+1,b+1+n);
    long long sum=0;
    for(long long i=1;i<=n;i++)
    {
        sum+=b[i]*i;
        s[i]=s[i-1]+b[i];
    }
    long long q;
    scanf("%lld",&q);
    while(q--)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        if(v<a[u])
        {
            long long x=lower_bound(b+1,b+1+n,v)-b;
            long long y=upper_bound(b+1,b+1+n,a[u])-b;
            long long ans=sum-(y-1)*b[y-1]+s[y-2]-s[x-1]+x*v;
            printf("%lld\n",ans);
            continue;
        }
        long long x=lower_bound(b+1,b+1+n,a[u])-b;
        long long y=upper_bound(b+1,b+1+n,v)-b;
        long long ans=sum-x*b[x]-s[y-1]+s[x]+(y-1)*v;
        printf("%lld\n",ans);
    }
    return 0;
}
